from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict


def apply_dynamic_filters(
    search_results: List[SearchResult],
    filter_specs: Dict[str, Dict[str, Any]],
    filter_logic: str = "AND"
) -> List[SearchResult]:
    """Apply dynamic metadata filters to search results with configurable logic.

    Args:
        search_results: List of SearchResult objects to filter
        filter_specs: Dictionary of filter specifications.
            Format: {"field_name": {"operator": value}}
            Example: {"category": {"==": "tech"}, "rating": {">=": 4.0}}
        filter_logic: "AND" (all filters must match) or "OR" (any filter matches)

    Returns:
        Filtered list of SearchResult objects
    """
    # Convert SearchResult objects to dictionaries
    result_dicts = []
    for result in search_results:
        result_dicts.append({
            'id': result.id,
            'score': result.score,
            'text': result.text,
            'metadata': result.metadata.to_dict() if hasattr(result.metadata, 'to_dict') else dict(result.metadata)
        })

    if not filter_specs:
        return search_results

    # Create individual filters for each condition
    conditions = []
    for field_name, condition_dict in filter_specs.items():
        for operator, value in condition_dict.items():
            conditions.append({
                'field_name': field_name,
                'operator': operator,
                'value': value
            })

    filter_engine = MetadataFilterEngine()
    individual_filters = []
    for condition in conditions:
        individual_filters.append(filter_engine.build_filter([condition], logic='AND'))

    def combined_filter(result_dict):
        if filter_logic == 'AND':
            return all(f(result_dict) for f in individual_filters)
        else:  # OR
            return any(f(result_dict) for f in individual_filters)

    filtered_dicts = [d for d in result_dicts if combined_filter(d)]

    # Convert back to SearchResult objects
    filtered_results = []
    for result_dict in filtered_dicts:
        filtered_results.append(SearchResult(
            id=result_dict['id'],
            score=result_dict['score'],
            text=result_dict['text'],
            metadata=result_dict['metadata']
        ))

    return filtered_results

