    if aggregation_funcs is None:
        # Default case: track score statistics
        for result in search_results:
            group_value = result.metadata.get(group_by_field) or 'unknown'
            group_data = groups[group_value]

            score = result.score
            group_data['scores'] = group_data.get('scores', []) + [score]
            group_data['sum_score'] = group_data.get('sum_score', 0) + score
            group_data['count'] = group_data.get('count', 0) + 1
            group_data['max_score'] = max(group_data.get('max_score', score), score)
            group_data['min_score'] = min(group_data.get('min_score', score), score)
    else:
        # Custom case: track specified fields
        for result in search_results:
            group_value = result.metadata.get(group_by_field) or 'unknown'
            group_data = groups[group_value]

            for field_name, func in aggregation_funcs.items():
                value = result.metadata.get(field_name)
                if value is not None:
                    group_data.setdefault(field_name, []).append(value)

    result_dict = {}

    for group_value, group_data in groups.items():
        group_stats = {}

        if aggregation_funcs is None:
            # Use default statistics
            scores = group_data['scores']
            count = len(scores)
            avg_score = sum(scores) / count if count > 0 else 0
            group_stats = {
                'count': count,
                'avg_score': avg_score,
                'max_score': max(scores),
                'min_score': min(scores)
            }
        else:
            # Use custom aggregation functions
            for field_name, func in aggregation_funcs.items():
                values = group_data.get(field_name, [])
                group_stats[field_name] = func(values)

        result_dict[group_value] = group_stats

    return result_dict

