def build_index_from_json_documents(
    json_file_path: str,
    index_path: str,
    text_field: str = "text",
    metadata_fields: Optional[List[str]] = None,
    backend_name: str = "hnsw"
) -> str:
    """Build a LEANN index from a JSON file containing documents."""
    json_path = Path(json_file_path)
    if not json_path.exists():
        raise FileNotFoundError(f"JSON file not found: {json_file_path}")

    try:
        with open(json_path, 'r', encoding='utf-8') as f:
            documents = json.load(f)
    except json.JSONDecodeError:
        raise ValueError("Invalid JSON file")

    if not isinstance(documents, list):
        raise ValueError("JSON file must contain a list of documents")

    # Validate each document has the text_field
    for i, doc in enumerate(documents):
        if not isinstance(doc, dict):
            raise ValueError(f"Document at index {i} is not a dictionary")
        if text_field not in doc:
            raise ValueError("missing required field")

    # Process metadata fields
    texts = []
    metadata_list = []

    for doc in documents:
        text = doc[text_field]
        texts.append(text)

        if metadata_fields is None:
            # Include all fields except text_field
            metadata_dict = {k: v for k, v in doc.items() if k != text_field}
        else:
            # Include only specified metadata fields that exist in the document
            metadata_dict = {}
            for field in metadata_fields:
                if field in doc:
                    metadata_dict[field] = doc[field]

        metadata_list.append(metadata_dict)

    # Build the index
    builder = LeannBuilder(backend_name=backend_name)
    builder.add_texts(texts, metadata=metadata_list)
    builder.build_index(index_path)

    return index_path

