def get_passages_by_metadata_range(
    index_path: str,
    field_name: str,
    min_value: float,
    max_value: float
) -> List[Dict[str, Any]]:
    """Retrieve all passages from an index where a numeric metadata field falls within a specified range."""
    if min_value > max_value:
        raise ValueError("min_value must be less than or equal to max_value")

    index_file = Path(index_path)
    if not index_file.exists():
        raise FileNotFoundError(f"Index file not found: {index_path}")

    pm = PassageManager(index_path)

    result = []
    for passage in pm:
        if field_name in passage.metadata:
            value = passage.metadata[field_name]
            if isinstance(value, (int, float)) and min_value <= value <= max_value:
                result.append(passage.to_dict())

    return result

