def search_with_result_limit_per_field(
    index_path: str,
    query: str,
    limit_field: str,
    max_per_value: int = 2,
    top_k: int = 10
) -> List[SearchResult]:
    """Search in an index and limit results per metadata field value."""
    if max_per_value <= 0:
        raise ValueError("max_per_value must be greater than 0")

    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError:
        raise FileNotFoundError(f"Index file not found: {index_path}")

    search_results = searcher.search(query, top_k=top_k)

    counts = {}
    limited_results = []
    for result in search_results:
        field_value = result.metadata.get(limit_field)
        if field_value is None:
            continue  # Skip results without the specified metadata field
        if counts.get(field_value, 0) < max_per_value:
            limited_results.append(result)
            counts[field_value] = counts.get(field_value, 0) + 1

    return limited_results

from typing import List, Dict, Any
from leann.api import LeannSearcher, SearchResult
import os

def search_with_result_merging(
    index_path: str,
    queries: List[str],
    top_k_per_query: int = 3,
    global_top_k: int = 10
) -> List[SearchResult]:
    """Search an index with multiple queries and merge results."""
    if not queries:
        raise ValueError("queries list cannot be empty")

    if not os.path.exists(index_path):
        raise FileNotFoundError(f"Index file not found: {index_path}")

    try:
        searcher = LeannSearcher(index_path)
    except Exception as e:
        # Re-raise with appropriate message if file-related error
        if "file" in str(e).lower() and ("not found" in str(e).lower() or "access" in str(e).lower()):
            raise FileNotFoundError(f"Index file not found or inaccessible: {index_path}")
        raise  # Re-raise other exceptions

    merged_results = []
    seen_doc_ids = set()

    for query in queries:
        search_results = searcher.search(query, top_k=top_k_per_query)
        for result in search_results:
            doc_id = getattr(result, 'doc_id', None)
            if doc_id is not None and doc_id not in seen_doc_ids:
                merged_results.append(result)
                seen_doc_ids.add(doc_id)

    # Sort by score descending
    merged_results.sort(key=lambda x: x.score, reverse=True)

    return merged_results[:global_top_k]
